4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty grid when given empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells each having only one neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a block (2x2) unchanged as a still life (survival)", () => {
15	    const block = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result).toHaveLength(4);
18	    expect(result).toEqual(expect.arrayContaining([[0, 0], [1, 0], [0, 1], [1, 1]]));
19	  });
20	  it("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
21	    const cells = [[0, 1], [1, 1], [0, 0]];
22	    const result = nextGeneration(cells);
23	    expect(result).toEqual(expect.arrayContaining([[1, 0]]));
