1	const offsets = [-1, 0, 1];
2	
3	const neighborKeys = (x: number, y: number): string[] =>
4	  offsets.flatMap((dx) =>
5	    offsets
6	      .filter((dy) => dx !== 0 || dy !== 0)
7	      .map((dy) => `${x + dx},${y + dy}`)
8	  );
9	
10	const countNeighbors = (x: number, y: number, alive: Set<string>): number =>
11	  neighborKeys(x, y).filter((key) => alive.has(key)).length;
12	
13	export const nextGeneration = (grid: number[][]): number[][] => {
14	  const alive = new Set(grid.map(([x, y]) => `${x},${y}`));
15	  const survivors = grid.filter(([x, y]) => {
16	    const neighbors = countNeighbors(x, y, alive);
17	    return neighbors === 2 || neighbors === 3;
18	  });
19	  const deadNeighbors = new Set(
20	    grid.flatMap(([x, y]) => neighborKeys(x, y).filter((key) => !alive.has(key)))
21	  );
22	  const births = [...deadNeighbors]
23	    .map((key) => key.split(",").map(Number))
24	    .filter(([x, y]) => countNeighbors(x, y, alive) === 3);
25	  return [...survivors, ...births];
26	};
